import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {

  const navigate = useNavigate();

  // ✅ state
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // dummy doctor (later replace with API)
  const doctor = {
    id: 1,
    name: "Dr. John Smith",
    specialization: "Cardiologist",
    experience: "10+ Years",
    qualification: "MBBS, MD",
    about: "Experienced cardiologist with a strong background in treating heart-related conditions and patient care.",
  };

  // ✅ navigate to confirm page
  const handleBooking = () => {
    if (!date || !time) {
      alert("Please select date and time");
      return;
    }

    navigate("/confirm-appointment", {
      state: {
        doctor,
        date,
        time,
        doctor_id: doctor.id,
      },
    });
  };

  return (
    <div style={styles.container}>

      <Navbar />

      <div style={styles.main}>

        <div style={styles.card}>

          {/* Left */}
          <div style={styles.left}>
            <img
              src="https://cdn-icons-png.flaticon.com/512/387/387561.png"
              alt="doctor"
              style={styles.image}
            />
          </div>

          {/* Right */}
          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><strong>Specialization:</strong> {doctor.specialization}</p>
            <p><strong>Experience:</strong> {doctor.experience}</p>
            <p><strong>Qualification:</strong> {doctor.qualification}</p>

            <p style={styles.about}>
              <strong>About:</strong> {doctor.about}
            </p>

            {/* Booking */}
            <div style={styles.bookingSection}>

              <label>Select Date:</label>
              <input
                type="date"
                style={styles.input}
                value={date}
                onChange={(e) => setDate(e.target.value)}
              />

              <label>Select Time:</label>
              <select
                style={styles.input}
                value={time}
                onChange={(e) => setTime(e.target.value)}
              >
                <option value="">Select Time</option>
                <option value="10:00 AM">10:00 AM</option>
                <option value="11:00 AM">11:00 AM</option>
                <option value="02:00 PM">02:00 PM</option>
                <option value="04:00 PM">04:00 PM</option>
              </select>

              <button style={styles.button} onClick={handleBooking}>
                Book Appointment
              </button>

            </div>
          </div>

        </div>

      </div>

      <Footer />

    </div>
  );
}

export default Doctorprofile;

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },

  card: {
    display: "flex",
    backgroundColor: "white",
    borderRadius: "10px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    padding: "30px",
    width: "700px",
    gap: "30px",
  },

  left: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },

  image: {
    width: "150px",
    height: "150px",
    borderRadius: "50%",
  },

  right: {
    flex: 1,
  },

  about: {
    marginTop: "10px",
  },

  bookingSection: {
    marginTop: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  input: {
    padding: "8px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  button: {
    marginTop: "10px",
    padding: "10px",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
